import React, { useState, useContext } from 'react';
import { taxasIRT } from '../data/mockData';
import { AppContext } from '../App';
import { Colaborador } from '../types';

const Processamento: React.FC = () => {
  const { empresa, colaboradores } = useContext(AppContext);
  const ativos = colaboradores.filter(c => c.status === 'Ativo');
  
  const currentYear = new Date().getFullYear();
  const [selectedMonth, setSelectedMonth] = useState('Janeiro');
  const [selectedYear, setSelectedYear] = useState(currentYear.toString());

  const [showFormModal, setShowFormModal] = useState(false);
  const [showReceiptModal, setShowReceiptModal] = useState(false);
  const [selectedColab, setSelectedColab] = useState<Colaborador | null>(null);

  // Form states
  const [formSalario, setFormSalario] = useState(0);
  const [formFaltas, setFormFaltas] = useState(0);
  const [formAlimentacao, setFormAlimentacao] = useState(0);
  const [formTransporte, setFormTransporte] = useState(0);
  const [formFerias, setFormFerias] = useState(0);
  const [formAtavio, setFormAtavio] = useState(0);
  const [formHorasExtra, setFormHorasExtra] = useState(0);
  const [formBonus, setFormBonus] = useState(0);

  const calcularIRT = (baseSujeitaIRT: number) => {
    const escalao = taxasIRT.find(t => baseSujeitaIRT >= t.minimo && baseSujeitaIRT <= t.maximo);
    if (!escalao) return 0;
    const calc = ((baseSujeitaIRT - escalao.minimo) * (escalao.taxa / 100)) + escalao.parcelaAbt;
    return calc > 0 ? calc : 0;
  };

  const handleStartProcessar = (colab: Colaborador) => {
    setSelectedColab(colab);
    setFormSalario(colab.salarioBase || 0);
    setFormFaltas(0);
    setFormAlimentacao(30000); // Standard defaults
    setFormTransporte(20000);
    setFormFerias(0);
    setFormAtavio(0);
    setFormHorasExtra(0);
    setFormBonus(0);
    setShowFormModal(true);
  };

  const handleConfirmForm = (e: React.FormEvent) => {
    e.preventDefault();
    setShowFormModal(false);
    setShowReceiptModal(true);
  };

  const currentCalc = () => {
    const totalBruto = formSalario + formAlimentacao + formTransporte + formFerias + formAtavio + formHorasExtra + formBonus;
    const baseSalarioLiquidoFaltas = formSalario - formFaltas;
    
    const taxaINSS = empresa?.taxaINSS || 3;
    const valorINSS = baseSalarioLiquidoFaltas * (taxaINSS / 100);
    const baseIRT = baseSalarioLiquidoFaltas - valorINSS + formAlimentacao + formTransporte + formFerias + formAtavio + formHorasExtra + formBonus; 
    const valorIRT = calcularIRT(baseIRT);
    
    const totalDescontos = valorINSS + valorIRT + formFaltas;
    const salarioLiquido = totalBruto - totalDescontos;

    return { totalBruto, valorINSS, valorIRT, totalDescontos, salarioLiquido };
  };

  const handleImprimir = () => {
    window.print();
  };

  const handleGuardar = () => {
    alert('Recibo guardado com sucesso no sistema!');
  };

  const handleEnviarEmail = () => {
    if(selectedColab?.email) {
      alert(`Recibo enviado para o endereço: ${selectedColab.email}`);
    } else {
      alert('Colaborador não possui um endereço de e-mail registado.');
    }
  };

  return (
    <div className="p-8">
      <div className="flex items-center justify-between mb-8">
        <div>
          <h2 className="text-2xl font-black tracking-tight">Processamento de Salários</h2>
          <p className="text-slate-500">Gere a folha de pagamento do período selecionado.</p>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-8">
        <div className="bg-white dark:bg-slate-900 p-6 rounded-xl border border-slate-200 dark:border-slate-800">
          <label className="block text-sm font-medium text-slate-500 mb-2">Mês de Referência</label>
          <select value={selectedMonth} onChange={e => setSelectedMonth(e.target.value)} className="w-full bg-slate-50 dark:bg-slate-800 border-none rounded-lg focus:ring-primary p-2">
            {['Janeiro', 'Fevereiro', 'Março', 'Abril', 'Maio', 'Junho', 'Julho', 'Agosto', 'Setembro', 'Outubro', 'Novembro', 'Dezembro'].map(m => (
              <option key={m} value={m}>{m}</option>
            ))}
          </select>
        </div>
        <div className="bg-white dark:bg-slate-900 p-6 rounded-xl border border-slate-200 dark:border-slate-800">
          <label className="block text-sm font-medium text-slate-500 mb-2">Ano</label>
          <select value={selectedYear} onChange={e => setSelectedYear(e.target.value)} className="w-full bg-slate-50 dark:bg-slate-800 border-none rounded-lg focus:ring-primary p-2">
            {['2024', '2025', '2026', '2027'].map(y => (
              <option key={y} value={y}>{y}</option>
            ))}
          </select>
        </div>
        <div className="bg-white dark:bg-slate-900 p-6 rounded-xl border border-slate-200 dark:border-slate-800 flex items-center justify-between">
          <div>
            <p className="text-xs text-slate-500 uppercase font-bold">Status</p>
            <p className="text-sm font-medium text-emerald-500">Aberto</p>
          </div>
          <span className="material-symbols-outlined text-slate-300">event_available</span>
        </div>
      </div>

      <div className="bg-white dark:bg-slate-900 rounded-xl border border-slate-200 dark:border-slate-800 overflow-hidden shadow-sm">
        <div className="overflow-x-auto">
          <table className="w-full text-left">
            <thead className="bg-slate-50 dark:bg-slate-800/50 border-b border-slate-200 dark:border-slate-800">
              <tr>
                <th className="p-4 text-xs font-bold text-slate-500 uppercase tracking-wider">Colaborador</th>
                <th className="p-4 text-xs font-bold text-slate-500 uppercase tracking-wider">Cargo</th>
                <th className="p-4 text-xs font-bold text-slate-500 uppercase tracking-wider text-right">Salário Base</th>
                <th className="p-4 text-xs font-bold text-slate-500 uppercase tracking-wider text-center">Ação</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100 dark:divide-slate-800">
              {ativos.length === 0 ? (
                <tr>
                  <td colSpan={4} className="p-8 text-center text-slate-500">Nenhum colaborador ativo no sistema.</td>
                </tr>
              ) : ativos.map(c => (
                <tr key={c.id} className="hover:bg-slate-50 dark:hover:bg-slate-800/50 transition-colors">
                  <td className="p-4">
                    <div className="flex items-center gap-3">
                      <div className="size-10 rounded-full bg-primary/10 flex items-center justify-center text-primary font-bold text-xs uppercase">
                        {c.nome.substring(0, 2)}
                      </div>
                      <div>
                        <p className="text-sm font-semibold">{c.nome}</p>
                        <p className="text-xs text-slate-500">{c.email}</p>
                      </div>
                    </div>
                  </td>
                  <td className="p-4 text-sm">{c.cargo}</td>
                  <td className="p-4 text-right font-medium text-sm">{c.salarioBase.toLocaleString()} Kz</td>
                  <td className="p-4 text-center">
                    <button 
                      onClick={() => handleStartProcessar(c)}
                      className="text-primary border border-primary/20 hover:bg-primary/10 px-4 py-1.5 rounded-lg text-xs font-bold transition-colors"
                    >
                      Processar
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>

      {showFormModal && selectedColab && (
        <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-[60] p-4 backdrop-blur-sm">
          <div className="bg-white dark:bg-slate-900 rounded-xl max-w-lg w-full max-h-[90vh] overflow-y-auto shadow-2xl">
            <div className="p-6 border-b border-slate-200 dark:border-slate-800 flex items-start justify-between bg-slate-50/50 dark:bg-slate-800/20">
              <div>
                <h2 className="font-black text-xl text-slate-900 dark:text-white uppercase tracking-wider">Validar Processamento</h2>
                <div className="text-slate-500 text-sm mt-1">Colaborador: {selectedColab.nome}</div>
              </div>
              <button onClick={() => setShowFormModal(false)} className="p-2 hover:bg-slate-200 dark:hover:bg-slate-800 rounded-lg transition-colors">
                <span className="material-symbols-outlined">close</span>
              </button>
            </div>
            <form onSubmit={handleConfirmForm} className="p-6 space-y-4">
              <div className="space-y-1.5">
                <label className="text-sm font-semibold text-slate-700">Salário Base (Kz)</label>
                <input required type="text" inputMode="numeric" pattern="[0-9,.]*" value={formSalario === 0 ? '' : formSalario} onChange={e => {
                  const val = e.target.value.replace(/[^0-9]/g, '');
                  setFormSalario(val ? Number(val) : 0);
                }} placeholder="Ex: 250000" className="w-full px-3 py-2 bg-slate-50 border border-slate-200 rounded-lg outline-none focus:border-primary font-medium" />
              </div>
              
              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-1.5">
                  <label className="text-sm font-semibold text-slate-700">Subs. Alimentação</label>
                  <input type="text" inputMode="numeric" pattern="[0-9,.]*" value={formAlimentacao === 0 ? '' : formAlimentacao} onChange={e => {
                    const val = e.target.value.replace(/[^0-9]/g, '');
                    setFormAlimentacao(val ? Number(val) : 0);
                  }} placeholder="Ex: 30000" className="w-full px-3 py-2 bg-slate-50 border border-slate-200 rounded-lg outline-none focus:border-primary" />
                </div>
                <div className="space-y-1.5">
                  <label className="text-sm font-semibold text-slate-700">Subs. Transporte</label>
                  <input type="text" inputMode="numeric" pattern="[0-9,.]*" value={formTransporte === 0 ? '' : formTransporte} onChange={e => {
                    const val = e.target.value.replace(/[^0-9]/g, '');
                    setFormTransporte(val ? Number(val) : 0);
                  }} placeholder="Ex: 20000" className="w-full px-3 py-2 bg-slate-50 border border-slate-200 rounded-lg outline-none focus:border-primary" />
                </div>
                <div className="space-y-1.5">
                  <label className="text-sm font-semibold text-slate-700">Subs. Férias</label>
                  <input type="text" inputMode="numeric" pattern="[0-9,.]*" value={formFerias === 0 ? '' : formFerias} onChange={e => {
                    const val = e.target.value.replace(/[^0-9]/g, '');
                    setFormFerias(val ? Number(val) : 0);
                  }} placeholder="0" className="w-full px-3 py-2 bg-slate-50 border border-slate-200 rounded-lg outline-none focus:border-primary" />
                </div>
                <div className="space-y-1.5">
                  <label className="text-sm font-semibold text-slate-700">Subs. Atávio</label>
                  <input type="text" inputMode="numeric" pattern="[0-9,.]*" value={formAtavio === 0 ? '' : formAtavio} onChange={e => {
                    const val = e.target.value.replace(/[^0-9]/g, '');
                    setFormAtavio(val ? Number(val) : 0);
                  }} placeholder="0" className="w-full px-3 py-2 bg-slate-50 border border-slate-200 rounded-lg outline-none focus:border-primary" />
                </div>
                <div className="space-y-1.5">
                  <label className="text-sm font-semibold text-green-700">Horas Extra</label>
                  <input type="text" inputMode="numeric" pattern="[0-9,.]*" value={formHorasExtra === 0 ? '' : formHorasExtra} onChange={e => {
                    const val = e.target.value.replace(/[^0-9]/g, '');
                    setFormHorasExtra(val ? Number(val) : 0);
                  }} placeholder="0" className="w-full px-3 py-2 bg-green-50 border border-green-200 rounded-lg outline-none focus:border-green-400" />
                </div>
                <div className="space-y-1.5">
                  <label className="text-sm font-semibold text-green-700">Bónus/Prémio</label>
                  <input type="text" inputMode="numeric" pattern="[0-9,.]*" value={formBonus === 0 ? '' : formBonus} onChange={e => {
                    const val = e.target.value.replace(/[^0-9]/g, '');
                    setFormBonus(val ? Number(val) : 0);
                  }} placeholder="0" className="w-full px-3 py-2 bg-green-50 border border-green-200 rounded-lg outline-none focus:border-green-400" />
                </div>
              </div>

              <div className="pt-4 border-t border-slate-100">
                <div className="space-y-1.5 flex flex-col">
                  <label className="text-sm font-semibold text-red-600 flex items-center gap-1"><span className="material-symbols-outlined text-[16px]">warning</span> Faltas (Valor a descontar)</label>
                  <input type="text" inputMode="numeric" pattern="[0-9,.]*" value={formFaltas === 0 ? '' : formFaltas} onChange={e => {
                    const val = e.target.value.replace(/[^0-9]/g, '');
                    setFormFaltas(val ? Number(val) : 0);
                  }} placeholder="0" className="w-full px-3 py-2 bg-red-50 border border-red-200 text-red-700 rounded-lg outline-none focus:border-red-400" />
                </div>
              </div>
              
              <button type="submit" className="w-full mt-4 py-3 bg-primary text-white rounded-lg font-bold hover:bg-primary/90 flex items-center justify-center gap-2">
                <span className="material-symbols-outlined">calculate</span>
                Calcular Salário
              </button>
            </form>
          </div>
        </div>
      )}

      {showReceiptModal && selectedColab && (
        <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-4 backdrop-blur-sm">
          <div className="bg-white dark:bg-slate-900 rounded-xl max-w-3xl w-full max-h-[90vh] overflow-y-auto shadow-2xl">
            <div className="p-6 border-b border-slate-200 dark:border-slate-800 flex items-start justify-between bg-slate-50/50 dark:bg-slate-800/20 print:hidden">
              <div className="flex items-center gap-4">
                <img src="/logo.png" alt="Logo" className="w-12 h-12 object-contain" onError={(e) => { e.currentTarget.style.display = 'none'; }} />
                <div>
                  <h2 className="font-black text-xl text-slate-900 dark:text-white uppercase tracking-wider">{empresa?.nome || 'SALYA LTDA'}</h2>
                  <div className="text-slate-500 text-sm mt-1">
                    <p>NIF: {empresa?.nif || 'Não preenchido'} | {empresa?.endereco || '-'} | {empresa?.municipio}{empresa?.municipio && empresa?.provincia ? ', ' : ''}{empresa?.provincia}</p>
                  </div>
                </div>
              </div>
              <button onClick={() => setShowReceiptModal(false)} className="p-2 hover:bg-slate-200 dark:hover:bg-slate-800 rounded-lg transition-colors">
                <span className="material-symbols-outlined">close</span>
              </button>
            </div>
            
            <div className="p-8 pb-4 print:p-0 print:border-none print:shadow-none" id="receita-imprimivel">
              {/* Cabelhaço Impressão */}
              <div className="hidden print:block mb-6 pb-4 border-b-2 border-slate-800">
                <div className="flex items-center gap-4">
                  <img src="/logo.png" alt="Logo" className="w-16 h-16 object-contain" onError={(e) => { e.currentTarget.style.display = 'none'; }} />
                  <div>
                    <h2 className="font-black text-2xl uppercase tracking-wider">{empresa?.nome || 'Empresa'}</h2>
                    <p className="text-sm">NIF: {empresa?.nif || '-'} | {empresa?.endereco || '-'} | {empresa?.municipio}, {empresa?.provincia}</p>
                  </div>
                </div>
              </div>

              <div className="text-center mb-8 border-b-2 border-slate-800 pb-6">
                <h3 className="font-bold text-2xl mb-2 text-slate-900">RECIBO DE VENCIMENTO</h3>
                <p className="text-base text-slate-600 font-medium border border-slate-300 inline-block px-4 py-1 rounded-none">Período: {selectedMonth} / {selectedYear}</p>
                <p className="text-sm text-slate-500 mt-3 font-mono">Recibo Nº: REC-{String(Date.now()).slice(-8)}</p>
              </div>

              <div className="grid grid-cols-2 gap-y-6 gap-x-12 mb-8 bg-slate-50 dark:bg-slate-800 p-6 rounded-xl border border-slate-100 dark:border-slate-700 print:bg-transparent print:border-slate-300">
                <div>
                  <p className="text-xs text-slate-500 uppercase font-semibold mb-1">Colaborador</p>
                  <p className="font-bold text-lg">{selectedColab.nome}</p>
                  <p className="text-sm text-slate-600 dark:text-slate-400 mt-1">Cargo: {selectedColab.cargo}</p>
                  <p className="text-xs text-slate-500 mt-1">Nº Colaborador: {selectedColab.numeroColaborador || '-'}</p>
                  <p className="text-xs text-slate-500">Tipo de Contrato: {selectedColab.tipoContrato || 'Efectivo'}</p>
                  <p className="text-xs text-slate-500">Data de Admissão: {selectedColab.dataAdmissao || '-'}</p>
                </div>
                <div>
                  <p className="text-xs text-slate-500 uppercase font-semibold mb-1">Identificação Fiscal</p>
                  <p className="font-medium text-slate-700 dark:text-slate-300">NIF: <span className="font-mono">{selectedColab.nif}</span></p>
                  <p className="text-sm text-slate-600 dark:text-slate-400 mt-1">Nº INSS: <span className="font-mono">{selectedColab.inss || '-'}</span></p>
                  <p className="text-sm text-slate-600 dark:text-slate-400 mt-2">Banco: <span>{selectedColab.banco || '-'}</span></p>
                  <p className="text-xs text-slate-500">IBAN: <span className="font-mono">{selectedColab.iban || '-'}</span></p>
                </div>
              </div>

              <div className="space-y-2">
                <div className="flex justify-between font-bold text-slate-700 dark:text-slate-300 border-b border-slate-200 dark:border-slate-700 pb-2 mb-4">
                  <span>Rendimentos</span>
                  <span>Valor Líquido</span>
                </div>
                
                <div className="flex justify-between items-center py-1">
                  <span className="text-slate-600 dark:text-slate-400">Vencimento Base</span>
                  <span className="font-medium">{formSalario.toLocaleString()} Kz</span>
                </div>
                {formAlimentacao > 0 && (
                  <div className="flex justify-between items-center py-1">
                    <span className="text-slate-600 dark:text-slate-400">Subsídio de Alimentação</span>
                    <span className="font-medium">{formAlimentacao.toLocaleString()} Kz</span>
                  </div>
                )}
                {formTransporte > 0 && (
                  <div className="flex justify-between items-center py-1">
                    <span className="text-slate-600 dark:text-slate-400">Subsídio de Transporte</span>
                    <span className="font-medium">{formTransporte.toLocaleString()} Kz</span>
                  </div>
                )}
                {formFerias > 0 && (
                  <div className="flex justify-between items-center py-1">
                    <span className="text-slate-600 dark:text-slate-400">Subsídio de Férias</span>
                    <span className="font-medium">{formFerias.toLocaleString()} Kz</span>
                  </div>
                )}
                {formAtavio > 0 && (
                  <div className="flex justify-between items-center py-1">
                    <span className="text-slate-600 dark:text-slate-400">Subsídio de Atábio / Atávio</span>
                    <span className="font-medium">{formAtavio.toLocaleString()} Kz</span>
                  </div>
                )}
                {formHorasExtra > 0 && (
                  <div className="flex justify-between items-center py-1">
                    <span className="text-slate-600 dark:text-slate-400">Horas Extra</span>
                    <span className="font-medium">{formHorasExtra.toLocaleString()} Kz</span>
                  </div>
                )}
                {formBonus > 0 && (
                  <div className="flex justify-between items-center py-1">
                    <span className="text-slate-600 dark:text-slate-400">Bónus / Prémio</span>
                    <span className="font-medium">{formBonus.toLocaleString()} Kz</span>
                  </div>
                )}
                
                <div className="flex justify-between items-center py-3 border-t border-slate-100 dark:border-slate-800 font-semibold mb-4 mt-2">
                  <span>Total Bruto</span>
                  <span>{currentCalc().totalBruto.toLocaleString()} Kz</span>
                </div>
                
                <div className="flex justify-between font-bold text-slate-700 dark:text-slate-300 border-b border-slate-200 dark:border-slate-700 pb-2 mt-4 mb-4">
                  <span>Descontos</span>
                  <span>Valor Retido</span>
                </div>
                
                <div className="flex justify-between items-center py-1">
                  <span className="text-slate-600 dark:text-slate-400">Segurança Social (INSS {empresa?.taxaINSS || 3}%)</span>
                  <span className="font-medium text-red-500">- {currentCalc().valorINSS.toLocaleString()} Kz</span>
                </div>
                <div className="flex justify-between items-center py-1">
                  <span className="text-slate-600 dark:text-slate-400">Imposto sobre Rendimento (IRT)</span>
                  <span className="font-medium text-red-500">- {currentCalc().valorIRT.toLocaleString(undefined, { maximumFractionDigits: 2 })} Kz</span>
                </div>
                {formFaltas > 0 && (
                  <div className="flex justify-between items-center py-1">
                    <span className="text-slate-600 dark:text-slate-400">Faltas e Atrasos</span>
                    <span className="font-medium text-red-500">- {formFaltas.toLocaleString()} Kz</span>
                  </div>
                )}
                
                <div className="flex justify-between items-center py-3 border-t border-slate-100 dark:border-slate-800 font-semibold text-red-500 mt-2">
                  <span>Total Descontos</span>
                  <span>- {currentCalc().totalDescontos.toLocaleString(undefined, { maximumFractionDigits: 2 })} Kz</span>
                </div>
              </div>

              <div className="mt-8 pt-6 border-t-2 border-slate-200 dark:border-slate-700 print:mt-12">
                <div className="flex justify-between items-center p-4 bg-primary/5 dark:bg-primary/10 rounded-xl print:bg-transparent print:border-2 print:border-slate-300 print:text-black">
                  <span className="font-bold text-lg text-slate-700 dark:text-slate-200 print:text-black">Líquido a Receber</span>
                  <span className="text-2xl font-black text-primary print:text-black">
                    {currentCalc().salarioLiquido.toLocaleString(undefined, { maximumFractionDigits: 2 })} Kz
                  </span>
                </div>
                <p className="text-xs text-slate-500 text-center mt-4 print:text-left print:mt-8">
                  Pagamento a ser efetuado por transferência bancária (IBAN: {selectedColab.iban || 'Não preenchido'})
                </p>
              </div>

              <div className="mt-8 pt-6 border-t border-slate-200 flex flex-col items-center justify-center opacity-80 print:mt-12 print:border-t-2">
                <img src="/logo.png" alt="SALYA Logo" className="w-20 h-20 rounded-lg mb-2 object-contain bg-white p-1" onError={(e) => { e.currentTarget.style.display = 'none'; }} />
                <span className="text-[10px] font-bold text-slate-500">Documento gerado e processado pelo sistema SALYA</span>
              </div>
            </div>
            
            <div className="p-6 border-t border-slate-200 dark:border-slate-800 flex flex-wrap gap-4 bg-slate-50 dark:bg-slate-900 rounded-b-xl print:hidden">
              <button onClick={handleGuardar} className="flex-1 py-3 bg-primary/10 text-primary border border-primary/20 rounded-xl font-bold hover:bg-primary/20 transition-all flex items-center justify-center gap-2">
                <span className="material-symbols-outlined text-[20px]">save</span>
                Guardar Recibo
              </button>
              <button onClick={handleImprimir} className="flex-1 py-3 border border-slate-200 dark:border-slate-700 text-slate-700 dark:text-slate-300 rounded-xl font-bold hover:bg-slate-100 dark:hover:bg-slate-800 transition-all flex items-center justify-center gap-2">
                <span className="material-symbols-outlined text-[20px]">print</span>
                Imprimir
              </button>
              <button onClick={handleEnviarEmail} className="w-full mt-2 py-3.5 bg-primary text-white rounded-xl font-bold hover:bg-primary/90 transition-all flex items-center justify-center gap-2 shadow-lg shadow-primary/20">
                <span className="material-symbols-outlined">send</span>
                Enviar por Email
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default Processamento;
